def get_es_client():
    """Create and return an Elasticsearch client with connection pooling."""
    kwargs = {
        'hosts': [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
        'max_retries': 3,
        'retry_on_timeout': True,
        'request_timeout': 10,
        'maxsize': 25,  # Connection pool size for high traffic
    }

    if ES_USERNAME and ES_PASSWORD:
        kwargs['basic_auth'] = (ES_USERNAME, ES_PASSWORD)

    return Elasticsearch(**kwargs)


# Initialize ES client at module level for connection reuse
es_client = get_es_client()


def build_search_query(keyword, category=None, min_price=None, max_price=None,
                       in_stock=None, sort_by=None, sort_order='desc'):
    """Build an Elasticsearch query with optional filters."""
    must_clauses = []
    filter_clauses = []

    # Main keyword search with multi-match across relevant fields
    if keyword:
        must_clauses.append({
            'multi_match': {
                'query': keyword,
                'fields': [
                    'name^3',          # Boost product name matches
                    'name.autocomplete^2',
                    'description^1.5',
                    'brand^2',
                    'category^1.5',
                    'tags^1',
                    'sku'
                ],
                'type': 'best_fields',
                'fuzziness': 'AUTO',
                'prefix_length': 2,
                'minimum_should_match': '75%'
            }
        })

    # Category filter
    if category:
        filter_clauses.append({
            'term': {'category.keyword': category}
        })

    # Price range filter
    if min_price is not None or max_price is not None:
        price_range = {}
        if min_price is not None:
            price_range['gte'] = float(min_price)
        if max_price is not None:
            price_range['lte'] = float(max_price)
        filter_clauses.append({
            'range': {'price': price_range}
        })

    # In-stock filter
    if in_stock is not None:
        filter_clauses.append({
            'term': {'in_stock': in_stock}
        })

    query = {
        'bool': {
            'must': must_clauses if must_clauses else [{'match_all': {}}],
            'filter': filter_clauses
        }
    }

    # Build sort
    sort = []
    if sort_by:
        sort_field_map = {
            'price': 'price',
            'name': 'name.keyword',
            'rating': 'rating',
            'created': 'created_at',
            'popularity': 'popularity_score'
        }
        if sort_by in sort_field_map:
            sort.append({sort_field_map[sort_by]: {'order': sort_order}})

    # Always add relevance score as secondary sort
    sort.append('_score')

    return query, sort


def build_aggregations():
    """Build aggregations for faceted search."""
    return {
        'categories': {
            'terms': {
                'field': 'category.keyword',
                'size': 50
            }
        },
        'brands': {
            'terms': {
                'field': 'brand.keyword',
                'size': 50
            }
        },
        'price_ranges': {
            'range': {
                'field': 'price',
                'ranges': [
                    {'key': 'under_25', 'to': 25},
                    {'key': '25_to_50', 'from': 25, 'to': 50},
                    {'key': '50_to_100', 'from': 50, 'to': 100},
                    {'key': '100_to_200', 'from': 100, 'to': 200},
                    {'key': 'over_200', 'from': 200}
                ]
            }
        },
        'avg_price': {
            'avg': {
                'field': 'price'
            }
        },
        'in_stock_count': {
            'filter': {
                'term': {'in_stock': True}
            }
        }
    }


def format_search_results(es_response, page, page_size):
    """Format Elasticsearch response into a clean API response."""
    hits = es_response.get('hits', {})
    total = hits.get('total', {})
    total_count = total.get('value', 0) if isinstance(total, dict) else total

    products = []
    for hit in hits.get('hits', []):
        product = hit.get('_source', {})
        product['id'] = hit.get('_id')
        product['score'] = hit.get('_score')

        # Include highlights if available
        if 'highlight' in hit:
            product['highlights'] = hit['highlight']

        products.append(product)

    # Format aggregations/facets
    facets = {}
    aggs = es_response.get('aggregations', {})
    if aggs:
        if 'categories' in aggs:
            facets['categories'] = [
                {'name': bucket['key'], 'count': bucket['doc_count']}
                for bucket in aggs['categories'].get('buckets', [])
            ]
        if 'brands' in aggs:
            facets['brands'] = [
                {'name': bucket['key'], 'count': bucket['doc_count']}
                for bucket in aggs['brands'].get('buckets', [])
            ]
        if 'price_ranges' in aggs:
            facets['price_ranges'] = [
                {'range': bucket['key'], 'count': bucket['doc_count']}
                for bucket in aggs['price_ranges'].get('buckets', [])
            ]
        if 'avg_price' in aggs:
            facets['avg_price'] = aggs['avg_price'].get('value')
        if 'in_stock_count' in aggs:
            facets['in_stock_count'] = aggs['in_stock_count'].get('doc_count', 0)

    total_pages = (total_count + page_size - 1) // page_size if page_size > 0 else 0

    return {
        'products': products,
        'pagination': {
            'total': total_count,
            'page': page,
            'page_size': page_size,
            'total_pages': total_pages,
            'has_next': page < total_pages,
            'has_prev': page > 1
        },
        'facets': facets
    }


@app.route('/api/search', methods=['GET'])
def search_products():
    """
    Search products endpoint.

    Query Parameters:
        q (str): Search keyword (required)
        page (int): Page number (default: 1)
        page_size (int): Results per page (default: 20, max: 100)
        category (str): Filter by category
        min_price (float): Minimum price filter
        max_price (float): Maximum price filter
        in_stock (bool): Filter by stock availability
        sort_by (str): Sort field (price, name, rating, created, popularity)
        sort_order (str): Sort order (asc, desc)
        facets (bool): Include faceted aggregations (default: true)

    Returns:
        JSON response with products, pagination, and facets
    """
    start_time = datetime.utcnow()

    # Extract and validate query parameters
    keyword = request.args.get('q', '').strip()
    if not keyword:
        return jsonify({
            'error': 'Missing required parameter',
            'message': 'Query parameter "q" is required',
            'status': 400
        }), 400

    if len(keyword) > 500:
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'Query parameter "q" exceeds maximum length of 500 characters',
            'status': 400
        }), 400

    # Pagination
    try:
        page = max(1, int(request.args.get('page', DEFAULT_PAGE)))
        page_size = min(MAX_PAGE_SIZE, max(1, int(request.args.get('page_size', DEFAULT_PAGE_SIZE))))
    except (ValueError, TypeError):
        return jsonify({
            'error': 'Invalid parameter',
            'message': 'page and page_size must be valid integers',
            'status': 400
        }), 400

    # Filters
    category = request.args.get('category', None)

    min_price = request.args.get('min_price', None)
    max_price = request.args.get('max_price', None)
    try:
        if min_price is not None:
            min_price = float(min_price)
            if min_price < 0:
                raise ValueError("min_price must be non-negative")
        if max_price is not None:
            max_price = float(max_price)
            if max_price < 0:
                raise ValueError("max_price must be non-negative")
        if min_price is not None and max_price is not None and min_price > max_price:
            raise ValueError("min_price cannot be greater than max_price")
    except ValueError as e:
        return jsonify({
            'error': 'Invalid parameter',
            'message': str(e),
            'status': 400
        }), 400

    in_stock_param = request.args.get('in_stock', None)
    in_stock = None
    if in_stock_param is not None:
        in_stock = in_stock_param.lower() in ('true', '1', 'yes')

    sort_by = request.args.get('sort_by', None)
    sort_order = request.args.get('sort_order', 'desc')
    if sort_order not in ('asc', 'desc'):
        sort_order = 'desc'

    include_facets = request.args.get('facets', 'true').lower() in ('true', '1', 'yes')

    # Build the query
    query, sort = build_search_query(
        keyword=keyword,
        category=category,
        min_price=min_price,
        max_price=max_price,
        in_stock=in_stock,
        sort_by=sort_by,
        sort_order=sort_order
    )

    # Calculate offset
    from_offset = (page - 1) * page_size

    # Prevent deep pagination
    if from_offset + page_size > 10000:
        return jsonify({
            'error': 'Pagination limit exceeded',
            'message': 'Cannot paginate beyond 10,000 results. Please refine your search.',
            'status': 400
        }), 400

    # Build search body
    search_body = {
        'query': query,
        'sort': sort,
        'from': from_offset,
        'size': page_size,
        'highlight': {
            'fields': {
                'name': {'number_of_fragments': 1},
                'description': {'number_of_fragments': 2, 'fragment_size': 150}
            },
            'pre_tags': ['<em>'],
            'post_tags': ['</em>']
        },
        '_source': {
            'excludes': ['embedding', 'internal_notes']  # Exclude internal fields
        },
        'track_total_hits': True
    }

    if include_facets:
        search_body['aggregations'] = build_aggregations()

    # Add suggest for typo corrections
    search_body['suggest'] = {
        'text': keyword,
        'product_suggest': {
            'phrase': {
                'field': 'name.trigram',
                'size': 3,
                'gram_size': 3,
                'direct_generator': [{
                    'field': 'name.trigram',
                    'suggest_mode': 'popular'
                }],
                'highlight': {
                    'pre_tag': '<em>',
                    'post_tag': '</em>'
                }
            }
        }
    }

    try:
        # Execute search with request cache enabled for high traffic
        es_response = es_client.search(
            index=ES_INDEX,
            body=search_body,
            request_cache=True
        )
    except Exception as e:
        logger.error(f"Elasticsearch search error: {str(e)}", exc_info=True)
        return jsonify({
            'error': 'Search service unavailable',
            'message': 'An error occurred while processing your search. Please try again.',
            'status': 503
        }), 503

    # Format response
    result = format_search_results(es_response, page, page_size)

    # Add suggestions if available
    suggestions = []
    suggest_data = es_response.get('suggest', {}).get('product_suggest', [])
    for entry in suggest_data:
        for option in entry.get('options', []):
            suggestions.append({
                'text': option.get('text'),
                'highlighted': option.get('highlighted'),
                'score': option.get('score')
            })
    if suggestions:
        result['suggestions'] = suggestions

    # Add metadata
    elapsed_ms = (datetime.utcnow() - start_time).total_seconds() * 1000
    result['meta'] = {
        'query': keyword,
        'took_ms': es_response.get('took', 0),
        'api_took_ms': round(elapsed_ms, 2),
        'timed_out': es_response.get('timed_out', False)
    }

    logger.info(
        f"Search query='{keyword}' page={page} results={result['pagination']['total']} "
        f"es_took={es_response.get('took', 0)}ms api_took={round(elapsed_ms, 2)}ms"
    )

    response = jsonify(result)
    # Cache headers for CDN/reverse proxy caching during high traffic
    response.headers['Cache-Control'] = 'public, max-age=30, stale-while-revalidate=60'
    response.headers['Vary'] = 'Accept-Encoding'

    return response, 200


@app.route('/api/search/suggest', methods=['GET'])
def search_suggest():
    """
    Autocomplete/suggestion endpoint for search-as-you-type.

    Query Parameters:
        q (str): Partial search keyword
        size (int): Number of suggestions (default: 5, max: 10)
    """
    keyword = request.args.get('q', '').strip()
    if not keyword or len(keyword) < 2:
        return jsonify({'suggestions': []}), 200

    try:
        size = min(10, max(1, int(request.args.get('size', 5))))
    except (ValueError, TypeError):
        size = 5

    search_body = {
        'size': 0,
        'suggest': {
            'product-suggest': {
                'prefix': keyword,
                'completion': {
                    'field': 'name.suggest',
                    'size': size,
                    'skip_duplicates': True,
                    'fuzzy': {
                        'fuzziness': 'AUTO'
                    }
                }
            }
        }
    }

    try:
        es_response = es_client.search(
            index=ES_INDEX,
            body=search_body,
            request_cache=True
        )
    except Exception as e:
        logger.error(f"Elasticsearch suggest error: {str(e)}", exc_info=True)
        return jsonify({'suggestions': []}), 200  # Graceful degradation

    suggestions = []
    suggest_data = es_response.get('suggest', {}).get('product-suggest', [])
    for entry in suggest_data:
        for option in entry.get('options', []):
            suggestions.append({
                'text': option.get('text'),
                'score': option.get('_score'),
                'id': option.get('_id')
            })

    response = jsonify({'suggestions': suggestions})
    response.headers['Cache-Control'] = 'public, max-age=60'
    return response, 200


@app.route('/api/search/health', methods=['GET'])
def health_check():
    """Health check endpoint for load balancers."""
    try:
        health = es_client.cluster.health(timeout='5s')
        es_status = health.get('status', 'unknown')
        is_healthy = es_status in ('green', 'yellow')

        return jsonify({
            'status': 'healthy' if is_healthy else 'unhealthy',
            'elasticsearch': {
                'status': es_status,
                'cluster_name': health.get('cluster_name'),
                'number_of_nodes': health.get('number_of_nodes'),
                'active_shards': health.get('active_shards')
            },
            'timestamp': datetime.utcnow().isoformat()
        }), 200 if is_healthy else 503
    except Exception as e:
        logger.error(f"Health check failed: {str(e)}")
        return jsonify({
            'status': 'unhealthy',
            'error': str(e),
            'timestamp': datetime.utcnow().isoformat()
        }), 503


